SELECT GENERO FROM (SELECT S.GENERO AS GENERO, COUNT(*) AS PARTICIPACOES FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON CH.SIAPE = S.PK_SIAPE JOIN CURSO C ON LOWER(CH.SIGLA_CURSO) = LOWER(C.SIGLA) WHERE LOWER(CH.AREA_INGRESSO) LIKE '%sociologia%' AND LOWER(CH.SIGLA_CAMPUS) = 'goi' AND LOWER(C.MODALIDADE) LIKE '%integrado%' AND LOWER(C.NIVEL) LIKE '%ensino medio%' AND CH.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4) AND S.GENERO IS NOT NULL GROUP BY S.GENERO ORDER BY PARTICIPACOES DESC LIMIT 1) AS t